//vip.opstream12.com/20220406/7985_230cbeea/index.m3u8"},{"name":"48","slug":"48","filename":"hanh-dong-pha-bang-tap-48","link_embed":"https://vip.opstream12.com/share/4158f6d19559955bae372bb00f6204e4","link_m3u8":"https://vip.opstream12.com/20220406/7986_8ee64134/index.m3u8"}]}],"time":"41M59S","description":"<p>Một nhóm buôn lậu ma túy xuyên quốc gia ngoài biên giới đang thông đồng với các thành phần bất hợp pháp ở địa phương Đông Sơn để thực hiện mưu đồ sản xuất Ma túy đá dưới ngầm với quy mô lớn nhằm đạt được mục đích cung cấp số lượng lớn cho những tỉnh của đại lục Trung Quốc và hải ngoại để thu về lợi nhuận cao. Trong hoàn cảnh nguy hiểm và phức tạp này thì các cảnh sát đội phòng chống ma túy do Lý Phi làm đại diện đã không ngần ngại hy sinh tính mạng để phá tan mạng lưới buôn bán Ma túy ngầm cực lớn được bảo hộ bởi những kẻ có ô dù lớn, và từng bước phá giải thế cục, để quyết sạch trướng ngại cho sự triển khai thuận lợi của “Hành động Chuyên án ma túy Lôi Đình”.</p>","tmdb":{"type":"tv","id":"89216","season":1,"vote_average":8.4,"vote_count":5},"modified":"2023-06-02T18:20:47.000Z"},{"id":"624d98a2c78eb57bbfe50b69","_id":"624d98a2c78eb57bbfe50b69","title":"Hộ Bảo Liên Minh Phần 2","origin_name":"Guardians of Ancient Magic","slug":"ho-bao-lien-minh-phan-2","year":2018,"type":"series","genre":[{"id":"620a220de0fc277084dfd16d","name":"Tình Cảm","slug":"tinh-cam"},{"id":"620a2238e0fc277084dfd291","name":"Tâm Lý","slug":"tam-ly"}],"country":[{"id":"62093063196e9f4ab6b448b8","name":"Trung Quốc","slug":"trung-quoc"}],"lang_key":"Vietsub","episode_current":"Hoàn Tất (12/12)","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"is_ai":false,"server_name":"Vietsub #1","server_data":[{"name":"1","slug":"1","filename":"ho-bao-lien-minh-phan-2-tap-1","link_embed":"https://vip.opstream12.com/share/e9287a53b94620249766921107fe70a3","link_m3u8":"https://vip.opstream12.com/20220406/7987_7edc2